from pathlib import Path
import base64
import gzip
import subprocess

path = Path('index.html')
text = path.read_text(encoding='utf-8')
if 'TAB_UI_COMFORT_V1' in text:
    raise SystemExit('Tab UI comfort patch already applied')

encoded = ''
patch = gzip.decompress(base64.b64decode(encoded))
subprocess.run(['git', 'apply', '--whitespace=nowarn', '-'], input=patch, check=True)

updated = path.read_text(encoding='utf-8')
required = ['TAB_UI_COMFORT_V1', 'tab-calendar', 'tab-plan', 'tab-student', 'tab-dept', 'tab-nuga', 'tab-request']
missing = [item for item in required if item not in updated]
if missing:
    raise SystemExit(f'Missing tab UI markers: {missing}')
if "const SHEET_ID = '10blDNZ4zjrFU5lwCvgtoD3npwIwcCMQTeqwPgpQ_Ffg';" not in updated:
    raise SystemExit('Sheet ID changed unexpectedly')
if 'AKfycbzk1DN0iDS7EdZvKq-iomzgxmiCzOwCUZwWZkN4fjvkzOZPdF1d3P9d1xt6Ii8VNnmmPQ' not in updated:
    raise SystemExit('Apps Script URL changed unexpectedly')
print('Applied consistent UI improvements to all tabs')